package main

import (
	"encoding/json"
	"fmt"
	"log"
	"net/http"

	"github.com/gorilla/mux"
)

type Comment struct {
	ID    string `json:"id"`
	Text  string `json:"text"`
	Name  string `json:"name"`
	Email string `json:"email"`
}

var comments = []Comment{
	{ID: "1", Text: "This is a comment from John Doe <john@example.com>", Name: "John Doe", Email: "john@example.com"},
	{ID: "2", Text: "This is another comment from Jane Smith <jane@example.com>", Name: "Jane Smith", Email: "jane@example.com"},
}

func getComments(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodGet {
		http.Error(w, "Invalid request method", http.StatusBadRequest)
		return
	}
	json.NewEncoder(w).Encode(comments)
}

func commentHandler(w http.ResponseWriter, r *http.Request) {
	vars := mux.Vars(r)
	id := vars["id"]
	for _, c := range comments {
		if c.ID == id {
			tmpl := template.Must(template.ParseFiles("comment.html"))
			err := tmpl.ExecuteTemplate(w, "comment.html", c)
			if err != nil {
				http.Error(w, err.Error(), http.StatusInternalServerError)
				return
			}
			return
		}
	}
	http.Error(w, "Comment not found", http.StatusNotFound)
}

func main() {
	r := mux.NewRouter()
	r.HandleFunc("/comments/{id}", commentHandler).Methods("GET")
	log.Fatal(http.ListenAndServe(":8080", r))
}